  SetMemberStatus(request: SetMemberStatusRequest): Promise<SetMemberStatusResponse>;
  // Soft-delete a member account (status='deleted').
  SoftDeleteMember(request: SoftDeleteMemberRequest): Promise<SoftDeleteMemberResponse>;
