  GenerateHackerInvite(request: GenerateHackerInviteRequest): Promise<GenerateHackerInviteResponse>;
  ListHackerInvites(request: ListHackerInvitesRequest): Promise<ListHackerInvitesResponse>;
  RevokeHackerInvite(request: RevokeHackerInviteRequest): Promise<RevokeHackerInviteResponse>;
  ListHackerAccounts(request: ListHackerAccountsRequest): Promise<ListHackerAccountsResponse>;
